  const [newCatStatus, setNewCatStatus] = useState('Активен');

  // Entry Point Placement States
  const [isPlacingEntryPointMode, setIsPlacingEntryPointMode] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
