                              ruleParam === 'block' ? 'bg-[#fff0e6] text-[#d97706]' :
                              ruleParam === 'flag_pro' ? 'bg-[#f3e8ff] text-[#7c3aed]' :
                              'bg-[#fffbeb] text-[#b45309]'
